{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표를 금요일 15:00 KST로 둔다.",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "result": "거절됨",
        "reason": "불일치 발생 시 패키지 설정과 계약을 먼저 확인하기로 결정했기 때문"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 목표일 뿐이며 최종 공개 릴리스 결정이 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "detail": "목요일까지 가능하면 검토하자는 제안이 있었으나 담당자는 지정되지 않음"
      },
      {
        "item": "최종 릴리스 승인권자",
        "detail": "결정되지 않음"
      },
      {
        "item": "릴리스 노트에 수요일 내부 목표를 언급할지 여부",
        "detail": "결정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음"
      },
      {
        "risk": "README 설치 단계가 오래된 상태이면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "릴리스 노트에 수요일 내부 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정됨",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정됨",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "정확한 마감 없음",
      "status": "확정됨",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "담당자 미지정",
      "source_certainty": "mentioned_not_assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md triage note 작성 여부",
      "스모크 결과 게시 후 Hara의 tarball 경로 확인 여부",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인권자 확정 여부",
      "릴리스 노트에 수요일 내부 stretch goal을 언급할지 여부"
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 만들지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 만들지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 만들지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 만들지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 만들지 않는다.",
    "owners": "명시된 담당자만 action item owner로 기록한다.",
    "deadlines": "명시된 마감만 due로 기록하고, Hara 작업처럼 정확한 마감이 없으면 없다고 표시한다."
  }
}
